    CountCharStep(s, i, 'z');
    CountCharStep(s, i, 'e');
    CountCharStep(s, i, 'r');
    CountCharStep(s, i, 'o');
    CountCharStep(s, i, 'n');
    if s[i] == 'z' {
      z := z + 1;
    } else if s[i] == 'e' {
      e := e + 1;
    } else if s[i] == 'r' {
      r := r + 1;
    } else if s[i] == 'o' {
